import {ClientRemoteObject, RemoteClient} from 'jibo-client-framework';
import {Event, EventContainer} from 'jibo-typed-events';
import {PlayStatus} from 'jibo-common-types';
import {DOFSet} from 'animation-utilities';

import parentLog from './log';
const log = parentLog.createChild('AnimationInstance');

/**
 * @description Enum of animation states
 * @typedef AnimationState
 * @prop INVALID
 * @prop PLAYING
 * @prop STOPPED
 * @prop STOPPING
 * @prop CANCELLED
 * @prop PAUSED
 * @prop RESUMED
 * @prop STARTED
 * @prop REJECTED
 */
export enum AnimationState {
    INVALID = 'INVALID',
    PLAYING = 'PLAYING',
    STOPPED = 'STOPPED',
    STOPPING = 'STOPPING',
    CANCELLED = 'CANCELLED',
    PAUSED = 'PAUSED',
    RESUMED = 'RESUMED',
    STARTED = 'STARTED',
    REJECTED = 'REJECTED',
}

/**
 * @interface AnimationInstanceEvents
 * @description Typed Events for an `AnimationInstance`.
 * @prop {Event<Object>} general Emits when any other event occurs. Passes in an object with
 *                               a `name` property, which is the event name, and a `payload`
 *                               property, which is the payload of the event.
 * @prop {Event<Object>} audio Emits when animation encounters an audio event. Passes in an
 *                             object with a `file` property.
 * @prop {Event<Object>} pixi Emits when animation encounters a pixi event. Passes in an
 *                            object with a `file` property.
 * @prop {Event<void>} holdSafe Emits when the animation encounters a "HOLD_SAFE" event.
 * @prop {Event<void>} stopped Emits when the animation stops. Usually use the resolution of `play`
 *                             to determine when this happens.
 * @prop {Event<void>} started Emits when the animation starts.
 * @prop {Event<void>} cancelled Emits when the animation is canceled by a higher priority system.
 * @prop {Event<void>} rejected Emits when the animation is is rejected since a higher priority
 * animation is currently playing.
 */
export class AnimationEvents extends EventContainer {
    general = new Event<{ name: string, payload: any }>('general');
    audio = new Event<{ file: string }>('audio');
    pixi = new Event<{ file: string, layerNum: number, attach: boolean, offset: string }>('pixi');
    holdSafe = new Event<void>('holdSafe');
    stopped = new Event<void>('stopped');
    cancelled = new Event<void>('cancelled');
    rejected = new Event<void>('rejected');
    started = new Event<void>('started');
    stateChange = new Event<AnimationState>('state changed');
}

/**
 * Handle to an animation instance. Can only be played *once*.
 * @class AnimationInstance
 */
export class AnimationInstance extends ClientRemoteObject {

    /**
     * Set of animation event emitters.
     * @type {AnimationInstanceEvents}
     * @name AnimationInstance#events
     */
    public events = new AnimationEvents();

    public AnimationState:typeof AnimationState = AnimationState;

    /**
     * Current state of the animation.
     * @type {AnimationState}
     * @name AnimationInstance#state
     */
    public state: AnimationState;

    private played = false;


    /**
     * Set of dofs this animation acts on.
     * @type {DOFSet}
     * @name AnimationInstance#dofs
     */
    constructor(protected client:RemoteClient, instanceId:number, public id:string, public dofs:DOFSet, didPlay:boolean = false) {
        super(client, {instanceId: instanceId});
        this.onEvent = this.onEvent.bind(this);
        this.on('EVENT', this.onEvent);
        if(didPlay){
            this.played = true;
            this.state = AnimationState.PLAYING;
        }
    }

    /**
     * Plays this animation on the robot.
     * @param {string} [requestor='Behavior'] The system making the animation request.
     * @returns {Promise<PlayStatus>} Resolves when the animation is finished playing or is canceled.
     * @method AnimationInstance#play
     */
    public async play(requestor:string = 'Behavior'):Promise<PlayStatus> {
        if(this.played){
            log.warn("Someone tried to play AnimationInstance "+this.id+" twice!");
            log.warn("Second Play Site:"+new Error().stack);
        }
        this.played = true;
        this.setState(AnimationState.PLAYING);
        return await this.sendMessage<PlayStatus>('play', [requestor]);
    }

    /**
     * Stops this animation if it is running.
     * @returns {Promise<void>} Resolves when the animation is stopped.
     * @method AnimationInstance#stop
     */
    public async stop():Promise<void> {
        this.setState(AnimationState.STOPPING);
        return await this.sendMessage<void>('stop');
    }

    /**
     * Pauses this animation if it is running.
     * @returns {Promise<void>} Resolves when the animation is paused.
     * @method AnimationInstance#pause
     */
    public async pause():Promise<void> {
        this.setState(AnimationState.PAUSED);
        return await this.sendMessage<void>('pause', [], true);
    }

    /**
     * Resumes this animation if it is paused.
     * @returns {Promise<void>} Resolves when the animation is resumed.
     * @method AnimationInstance#resume
     */
    public async resume():Promise<void> {
        this.setState(AnimationState.RESUMED);
        return await this.sendMessage<void>('resume', [], true);
    }

    /**
     * Removes all event listensers and
     * @method AnimationInstance#destroy
     */
    public destroy() {
        super.destroy();
        this.removeAllListeners();
        this.events.removeAllListeners();
    }

    private setState(newState: AnimationState) {
        const lastState = this.state;
        this.state = newState;
        if (lastState !== newState) {
            this.events.stateChange.emit(newState);
        }
    }

    private onEvent(eventName:string, payload:any) {
        if(eventName === 'play-audio') {
            this.events.audio.emit(payload);
        }
        else if(eventName === 'play-pixi') {
            this.events.pixi.emit(payload);
        }
        else if(eventName === 'HOLD_SAFE') {
            this.events.holdSafe.emit();
        }
        else if(eventName === AnimationState.STOPPED) {
            this.setState(AnimationState.STOPPED);
            this.events.stopped.emit();
            this.emit(AnimationState.STOPPED);
        }
        else if(eventName === AnimationState.STARTED) {
            this.setState(AnimationState.STARTED);
            this.events.started.emit();
            this.emit(AnimationState.STARTED);
        }
        else if(eventName === AnimationState.CANCELLED) {
            this.setState(AnimationState.CANCELLED);
            this.events.cancelled.emit();
            this.emit(AnimationState.CANCELLED);
        }
        else if(eventName === AnimationState.REJECTED) {
            this.setState(AnimationState.REJECTED);
            this.events.rejected.emit();
            this.emit(AnimationState.REJECTED);
        }
        else {
            this.events.general.emit({name: eventName, payload});
        }
    }
}
