import {ClientRemoteObject, RemoteClient} from 'jibo-client-framework';

import parentLog from './log';
const log = parentLog.createChild('ResolveHandle');

export class ResolveHandle<T> extends ClientRemoteObject {

    public promise:Promise<T>;
    public result:T;
    private resolvePromise:(result:T) => void;
    private canceled:boolean = false;
    private resolved:boolean = false;

    constructor(client: RemoteClient, options: {instanceId: number;}) {
        super(client, options);
        this.promise = new Promise<T>((res:(result:T) => void) => {
            this.resolvePromise = res;
        });
    }

    public async cancel():Promise<void> {
        if(this.resolved || this.canceled) {
            if(this.canceled) {
                log.info("Someone tried to cancel ResolveHandle after it was cancelled!");
                log.info("Second cancel site:"+new Error().stack);
            }else if(this.resolved){
                log.info("Someone tried to cancel ResolveHandle after it was resolved!");
            }
            this.canceled = true;
        }else{
            await this.sendMessage<void>('cancel', []);
            this.canceled = true;
            super.destroy();
        }
    }

    public async onPromise(result:T):Promise<void> {
        this.resolved = true;
        this.result = result;
        this.resolvePromise(result);
        super.destroy();
    }
}
