import * as ai_ns from './AnimationInstance';
// import {AnimationInstance, AnimationEvents} from './AnimationInstance';
import Expression from './Expression';
import {RemoteClient} from 'jibo-client-framework';
import {DOFSets} from 'animation-utilities';
import createDOFs from './DOFs';
import {Event} from 'jibo-typed-events';

import * as common_ns from 'jibo-common-types';
import * as anim_ns from 'animation-utilities';
import * as handles_ns from './handles';

//for convienence
export * from './AnimationInstance';
export * from './handles';


const client:RemoteClient = new RemoteClient('token');
const _expression:Expression = new Expression(client);

export {
    Expression,
    client //for tests
};

export namespace expression {

    /**
     * Set of attention modes to pass to the attention APIs.
     * @type {AttentionMode}
     * @name jibo.expression#AttentionMode
     */
    export import AttentionMode = common_ns.AttentionMode;

    //These are just types
    export import KinematicFeatures = common_ns.KinematicFeatures;
    export import KinematicFeature = common_ns.KinematicFeature;
    export import CloneOptions = common_ns.CloneOptions;
    export import AnimationOptions = common_ns.AnimationOptions;
    export import AwaitFaceOptions = common_ns.AwaitFaceOptions;
    export import AcquireOptions = common_ns.AcquireOptions;
    export import CenterOptions = common_ns.CenterOptions;
    export import CleanupOptions = common_ns.CleanupOptions;
    export import IndexRobotResult = common_ns.IndexRobotResult;
    export import AnimationInstance = ai_ns.AnimationInstance;
    export import AttentionHandle = handles_ns.AttentionHandle;
    export import AcquireHandle = handles_ns.AcquireHandle;
    export import AwaitFaceHandle = handles_ns.AwaitFaceHandle;
    export import DOFSet = anim_ns.DOFSet;

    export let events:{
        dofs:Event<{timestamp:[number, number], dofValues:any, metadata:any}>;
        kinematics:Event<KinematicFeatures>;
    };

    export let dofs:DOFSets;

    export let features:KinematicFeatures;

    export async function init(port:number, jibo:any):Promise<void> {
        expression.dofs = await createDOFs();
        _expression.dofs = expression.dofs;
        expression.events = _expression.events;
        expression.features = _expression.features;
        await client.init(port);
        await _expression.init(jibo);
    }

    export async function createAnimation(options:AnimationOptions<DOFSet>):Promise<AnimationInstance> {
        return await _expression.createAnimation(options);
    }

    export async function createAndPlayAnimation(options:AnimationOptions<DOFSet>, requestor:string = 'Behavior'):Promise<AnimationInstance> {
        return await _expression.createAndPlayAnimation(options, requestor);
    }

    export async function destroyCaches(cacheNames:string|string[]):Promise<void> {
        return await _expression.destroyCaches(cacheNames);
    }

    export async function acquireTarget(options:AcquireOptions):Promise<AcquireHandle> {
        return await _expression.acquireTarget(options);
    }

    export async function setAttentionMode(mode:AttentionMode):Promise<void> {
        return await _expression.setAttentionMode(mode);
    }

    export async function pushAttentionMode(mode:AttentionMode):Promise<AttentionHandle> {
        return await _expression.pushAttentionMode(mode);
    }

    export async function getAttentionMode():Promise<AttentionMode> {
        return await _expression.getAttentionMode();
    }

    export async function setLEDColor(color:[number, number, number]):Promise<void> {
        return await _expression.setLEDColor(color);
    }

    export async function awaitFace(options:AwaitFaceOptions = {timeout:10000}):Promise<AwaitFaceHandle> {
        return await _expression.awaitFace(options);
    }

    export async function centerRobot(options?:CenterOptions<DOFSet>):Promise<void> {
        return await _expression.centerRobot(options);
    }

    export async function cleanup(options?:CleanupOptions<DOFSet>):Promise<void> {
        return await _expression.cleanup(options);
    }

    export async function indexRobot():Promise<IndexRobotResult> {
        return await _expression.indexRobot();
    }

    export async function setSkillRoot(root:string):Promise<void> {
        return await _expression.setSkillRoot(root);
    }

    export async function blink():Promise<void> {
        return await _expression.blink();
    }

    export async function doCenterRobotOnDisconnect(allow:boolean):Promise<void> {
        return await _expression.doCenterRobotOnDisconnect(allow);
    }

}
