// --- Just for typings, not runtime dependency ---
import JiboImport = require('../../jibo');
type Emotion = JiboImport.emotion.Emotion;
type EmotionPoint = JiboImport.emotion.EmotionPoint;
// ------------------------------------------------

import {ClientRemoteObject, RemoteClient} from 'jibo-client-framework';
import {Event} from 'jibo-typed-events';
import {AnimationInstance} from './AnimationInstance';
import {
    AnimationOptions,
    AcquireOptions,
    AttentionMode,
    CenterOptions,
    CleanupOptions,
    IndexRobotResult,
    AwaitFaceOptions,
    AnimationInstantiateResult,
    InstantiateAndPlayResult,
    InstantiateResult,
    ExpressionIds,
    KinematicFeatures
} from 'jibo-common-types';
import {AttentionHandle} from './handles/AttentionHandle';
import {AcquireHandle} from './handles/AcquireHandle';
import {AwaitFaceHandle} from './handles/AwaitFaceHandle';
import {DOFSets, DOFSet, THREE} from 'animation-utilities';

/**
 * @description
 * Jibo's Expression Client
 * @namespace jibo.expression
 */
class Expression extends ClientRemoteObject {

    /**
     * @interface ExpressionEvents
     * @description Typed Events for expression module (`jibo.expression.events`)
     * @prop {Event<DOFEventData>} dofs
     * @prop {Event<KinematicFeatures>} kinematics
     */

     /**
      * Results returned when await face is resolved.
      * @interface DOFEventData
      * @prop {number[]} timestamp
      * @prop {Object} dofValues Associative array of dof names to values.
      * @prop {Object} metadata Any metadata associated with display values.
      */

    /**
     * A set of event emitters that capture high frequency updates from the expression service
     * @type {ExpressionEvents}
     * @name jibo.expression#events
     */
    public events:{
        dofs:Event<{timestamp:[number, number], dofValues:any, metadata:any}>;
        kinematics:Event<KinematicFeatures>;
    };

    /**
     * A convienent assortment of DOF sets for playing animations.
     * @type {DOFSets}
     * @name jibo.expression#dofs
     */
    public dofs:DOFSets;

    /**
     * The most current `KinematicFeatures` received by the expression client.
     * @type {KinematicFeatures}
     * @name jibo.expression#features
     */
    public features:KinematicFeatures;

    /**
     * The Jibo runtime.
     * This should not be a part of the external API.
     * @private
     */
    private jibo:typeof JiboImport;

    constructor(protected client:RemoteClient) {
        super(client, {instanceId: ExpressionIds.EXPRESSION});
        this.onDofEvent = this.onDofEvent.bind(this);
        this.onKinematicEvent = this.onKinematicEvent.bind(this);
        this.on('dofs', this.onDofEvent);
        this.on('kinematics', this.onKinematicEvent);
        this.events = {
            dofs: new Event<{timestamp:[number, number], dofValues:any, metadata:any}>('dofs'),
            kinematics: new Event<any>('kinematics')
        };
        this.features = {
            base: {
                position: new THREE.Vector3(),
                direction: new THREE.Vector3()
            },
            eye: {
                position: new THREE.Vector3(),
                direction: new THREE.Vector3()
            },
            head: {
                position: new THREE.Vector3(),
                direction: new THREE.Vector3()
            }
        };
    }

    public async init(jibo:any):Promise<void> {
        this.jibo = jibo;
        //don't try to use the timer if there isn't one (don't need to send emotion state in SSM)
        if (this.jibo.timer) {
            this.jibo.timer.setInterval(() => {
                this.sendEmotionState();
            }, 500);
        }
    }

    /**
     * Creates an animation object on the expression server. If no `cacheName` is added, this animation will
     * persist on the server forever. Returns a `Promise` that resolves to an `AnimationInstance`.
     * @param {AnimationOptions} options Options to specify.
     * @returns {Promise<AnimationInstance>} Resolves to an `AnimationInstance`.
     * @method jibo.expression#createAnimation
     */
    public async createAnimation(options:AnimationOptions<DOFSet>):Promise<AnimationInstance> {
        let arg:any = options;
        if(arg.dofs) {
            arg.dofs = arg.dofs.getDOFs();
        }
        const result = await this.sendMessage<AnimationInstantiateResult>('createAnimation', [arg]);
        const dofs:DOFSet = (this.dofs.ALL as any).createFromDofs(result.state.dofs);
        return new AnimationInstance(
            this.client, result.instanceId, result.state.id, dofs
        );
    }

    /**
     * Creates and immediately plays an animation on the expression server.
     * Returns a `Promise` that resolves to an `AnimationInstance`.
     * Event handlers for `stopped`, `cancelled`, `rejected`, and other animation events must be registered to the
     * `AnimationInstance` immediately (in-stack) upon promise resolution, or else they may be missed.
     * @param {AnimationOptions} options Options to specify.
     * @param {string} [requestor='Behavior'] The system making the animation request.
     * @returns {Promise<AnimationInstance>} Resolves to an `AnimationInstance`.
     * @method jibo.expression#createAndPlayAnimation
     */
    public async createAndPlayAnimation(options:AnimationOptions<DOFSet>, requestor:string = 'Behavior'):Promise<AnimationInstance> {
        let arg:any = options;
        if(arg.dofs) {
            arg.dofs = arg.dofs.getDOFs();
        }
        const result = await this.sendMessage<InstantiateAndPlayResult>('createAndPlayAnimation', [arg, requestor]);
        const dofs:DOFSet = (this.dofs.ALL as any).createFromDofs(result.instantiateResult.state.dofs);
        return new AnimationInstance(
            this.client, result.instantiateResult.instanceId, result.instantiateResult.state.id, dofs, true
        );
    }

    /**
     * Destroys caches saved in the expression service.
     * @param {(string|string[])} cacheNames A cache name or array of cacheNames to destroy.
     * @returns {Promise<void>}
     * @method jibo.expression#destroyCaches
     */
    public async destroyCaches(cacheNames:string|string[]):Promise<void> {
        return await this.sendMessage<void>('destroyCaches', [cacheNames], true);
    }

    /**
     * @description Move Jibo's face to look at a target.
     * @method jibo.expression#acquireTarget
     * @param {AcquireOptions}          options             Options to specify.
     * @returns {Promise<AcquireHandle>}
     */
    public async acquireTarget(options:AcquireOptions):Promise<AcquireHandle> {
        const result = await this.sendMessage<InstantiateResult<void>>('acquireTarget', [options]);
        const handle:AcquireHandle = new AcquireHandle(
            this.client, {instanceId: result.instanceId}
        );
        return handle;
    }


    /**
     * Sets the mode of attention.
     * @param {AttentionMode} mode Mode to set.
     * @returns {Promise<void>}
     * @method jibo.expression#setAttentionMode
     */
    public async setAttentionMode(mode:AttentionMode):Promise<void> {
        await this.sendMessage<void>('setAttentionMode', [mode], true);
    }

    /**
     * Sets the mode governing the attention system's behavior for a bounded time period.
     * Returns a promise to an `AttentionHandle` which MUST have `release()` called on it when
     * the caller is finished with the mode.
     *
     * Modes are maintained in a stack: the most recent call to `pushMode` will always win, and when
     * a handle is released, it will drop down to mode of the highest non-released mode.
     *
     * Mode stack is fully cleared when `setMode` is called, and that mode becomes the base mode
     * for when a stack is fully released.
     *
     * @method jibo.expression#pushAttentionMode
     * @param {AttentionMode} mode - The new attention system mode: `IDLE`, `ENGAGED`, `SPEAKING`, `OFF`, etc.
     * @return {Promise<AttentionHandle>} The handle for this mode request. MUST call `release()` on this handle when finished.
     */
    public async pushAttentionMode(mode:AttentionMode):Promise<AttentionHandle> {
        const result = await this.sendMessage<InstantiateResult<void>>('pushAttentionMode', [mode]);
        const handle:AttentionHandle = new AttentionHandle(this.client, {instanceId: result.instanceId});
        return handle;
    }

    /**
     * Gets the current mode of the attention system.
     * @method jibo.expression#getAttentionMode
     * @returns {AttentionMode} The current attention system mode.
     */
    public async getAttentionMode():Promise<AttentionMode> {
        return await this.sendMessage<AttentionMode>('getAttentionMode');
    }

    /**
     * Sets the color of the LED.
     * @param {number[]} color An array or RGB values with range of `[0,1]`.
     * @method jibo.expression#setLEDColor
     * @returns {Promise<void>}
     */
    public async setLEDColor(color:[number, number, number]):Promise<void> {
        return await this.sendMessage<void>('setLEDColor', [color], true);
    }


    // TODO -> implement these functions
    // public async pushLEDMode(mode:LEDMode):Promise<LEDHandle> {
    //     const instanceId:number = await this.sendMessage<number>('pushLEDMode', [mode]);
    //     const handle:LEDHandle = new LEDHandle(this.client, {instanceId});
    //     return handle;
    // }

    // public async getLEDMode():Promise<LEDMode> {
    //     return await this.sendMessage<LEDMode>('getLEDMode');
    // }

    /**
     * Asynchronously waits for a face to appear.
     * Returns a promise that resolves to a cancelable handle with a promise that will resolve when a face is detected or timeout is reached.
     * Faces that are already in view "count" - so, the command may resolve quickly if people are already present.
     * @method jibo.expression#awaitFace
     * @param {AwaitFaceOptions} options - Options to specify.
     * @return {Promise<AwaitFaceHandle>} A promise that resolves to a cancelable command handle.
     */
    public async awaitFace(options:AwaitFaceOptions = {timeout:10000}):Promise<AwaitFaceHandle> {
        const result = await this.sendMessage<InstantiateResult<void>>('awaitFace', [options]);
        const handle:AwaitFaceHandle = new AwaitFaceHandle(
            this.client,{instanceId: result.instanceId}
        );
        return handle;
    }

    /**
     * Centers the robot in an upright position.
     * @param {CenterOptions} [options] Options to specify.
     * @method jibo.expression#centerRobot
     * @returns {Promise<void>} Resolves when done centering.
     */
    public async centerRobot(options?:CenterOptions<DOFSet>):Promise<void> {
        if(!options) {
            options = {};
        }
        if(!options.requestor) {
            options.requestor = 'Behavior';
        }
        const arg:any = options;
        if(options.dofs) {
            arg.dofs = options.dofs.getDOFs();
        }
        await this.sendMessage('centerRobot', [arg]);
    }

    /**
     * Cleans up the currently animated state, centering the robot and releasing ownership for the next use site.
     * @param {CleanupOptions} [options] Cleanup options.
     * @method jibo.expression#cleanup
     * @returns {Promise<void>} Resolves when the cleanup command is sent to the expression system.
     */
    public async cleanup(options?:CleanupOptions<DOFSet>):Promise<void> {
        if(!options) {
            options = {};
        }
        if(!options.requestor) {
            options.requestor = 'Behavior';
        }
        const arg:any = options;
        if(options.dofs) {
            arg.dofs = options.dofs.getDOFs();
        }
        await this.sendMessage('cleanup', [arg], true);
    }

    /**
     * Fully indexes the robot.
     * @returns {Promise<IndexRobotResult>} Resolves when done indexing.
     * @method jibo.expression#indexRobot
     */
    public async indexRobot():Promise<IndexRobotResult> {
        return await this.sendMessage<IndexRobotResult>('indexRobot');
    }

    public async setSkillRoot(root:string):Promise<void> {
        this.client.on('reopen', () => {
            this.sendMessage<void>('setSkillRoot', [root], true);
        });
        await this.sendMessage<void>('setSkillRoot', [root], true);
    }

    /**
     * Makes Jibo perform a procedural blink.
     * @returns {Promise<void>} Resolves when the expression system receives the blink command.
     * @method jibo.expression#blink
     */
    public async blink():Promise<void> {
        await this.sendMessage('blink', [], true);
    }

    /**
     * Allow or disallow the expression service to move into a final pose when shutting down.
     */
    public async doCenterRobotOnDisconnect(allow:boolean):Promise<void> {
        await this.sendMessage('doCenterRobotOnDisconnect', [allow], false);
    }

    private sendEmotionState() {
        //don't try to send emotion changes in the SSM
        if (!this.jibo.emotion) {
            return;
        }
        const currentEmotionValues:EmotionPoint = this.jibo.emotion.getCurrentEmotionalValues();
        const nearestEmotion:Emotion = this.jibo.emotion.getNearestEmotion();
        this.sendMessage('acceptEmotionState', [currentEmotionValues, nearestEmotion.name, nearestEmotion.emotionValues], true);
    }

    private onDofEvent(timestamp:[number, number], dofValues:any, metadata:any) {
        this.events.dofs.emit({
            timestamp, dofValues, metadata
        });
    }

    private onKinematicEvent(features:any) {

        this.applyVec(this.features.head.position, features.head.position);
        this.applyVec(this.features.head.direction, features.head.direction);

        this.applyVec(this.features.eye.position, features.eye.position);
        this.applyVec(this.features.eye.direction, features.eye.direction);

        this.applyVec(this.features.base.position, features.base.position);
        this.applyVec(this.features.base.direction, features.base.direction);

        this.events.kinematics.emit(this.features);
    }

    private applyVec(to:THREE.Vector3, from:THREE.Vector3) {
        to.x = from.x;
        to.y = from.y;
        to.z = from.z;
    }
}

export default Expression;
