/**
 * Releasable handle for attention mode stack.
 * @class AttentionHandle
 */
export class AttentionHandle extends ReleaseHandle<boolean> {
	constructor(
		client: RemoteClient,
		options: {
			instanceId: number;
		}
	){
		super(client, options, false);
	}
}

