import {ClientRemoteObject, RemoteClient} from 'jibo-client-framework';

import parentLog from './log';
const log = parentLog.createChild('ReleaseHandle');

export class ReleaseHandle<T> extends ClientRemoteObject {

    private released:boolean = false;
    private valToReturnWhenAlreadyReleased:T;

    constructor(
        client: RemoteClient,
        options: {
            instanceId: number;
        },
        valToReturnWhenAlreadyReleased:T){
        super(client, options);
        this.valToReturnWhenAlreadyReleased = valToReturnWhenAlreadyReleased;
    }


    public async release():Promise<T> {
        if(this.released) {
            log.info("Someone tried to release ReleaseHandle twice!");
            log.info("Second release site:"+new Error().stack);
            return this.valToReturnWhenAlreadyReleased;
        }else{
            this.released = true;
            try {
                return await this.sendMessage<T>('release');
            } finally {
                super.destroy();
            }
        }
    }
}
